import os
import openai
from langchain import OpenAI, VectorDB, RetrievalAugmentedGeneration
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS
from langchain.prompts import PromptTemplate
from langchain.chains import RetrievalAugmentedGenerationChain

# Load environment variables securely
openai_api_key = os.getenv('OPENAI_API_KEY')
vector_db_path = os.getenv('VECTOR_DB_PATH')

# Validate environment variables
if not openai_api_key or not vector_db_path:
    raise ValueError("Missing required environment variables")

# Initialize OpenAI API securely
openai.api_key = openai_api_key

# Load documents into vector database
def load_documents_to_vector_db(documents, vector_db_path):
    embeddings = OpenAIEmbeddings(api_key=openai_api_key)
    vector_db = FAISS.from_documents(documents, embeddings)
    vector_db.save(vector_db_path)

# Load vector database
def load_vector_db(vector_db_path):
    embeddings = OpenAIEmbeddings(api_key=openai_api_key)
    return FAISS.load(vector_db_path, embeddings)

# Securely handle user queries
def handle_user_query(query, vector_db):
    if not isinstance(query, str) or len(query) > 1000:
        raise ValueError("Invalid query input")

    # Retrieve relevant documents
    retrieved_docs = vector_db.similarity_search(query, k=5)

    # Construct prompt with retrieved documents
    prompt_template = PromptTemplate(
        template="Given the following documents: {documents}\nAnswer the question: {query}",
        input_variables=["documents", "query"]
    )
    prompt = prompt_template.format(documents=retrieved_docs, query=query)

    # Generate response using LLM
    rag_chain = RetrievalAugmentedGenerationChain(
        llm=OpenAI(api_key=openai_api_key),
        retriever=vector_db,
        prompt_template=prompt_template
    )
    response = rag_chain.run(query=query)

    return response

# Example usage
documents = ["Company policy document 1", "Company policy document 2"]
load_documents_to_vector_db(documents, vector_db_path)
vector_db = load_vector_db(vector_db_path)
user_query = "What is the company's policy on remote work?"
response = handle_user_query(user_query, vector_db)
print(response)